dslRule:
/*!id: jdt.internal.switchcase.getexpression2.to.getexpressions*/
/*!description: Updates internal JDT DOM AST accessors for SwitchCase, renaming getExpression2() to getExpressions() for Java 12+ Switch Expressions support.*/
/*!severity: info*/
/*!minJavaVersion: 12*/
org.eclipse.jdt.core.dom.SwitchCase.$node.getExpression2() :: sourceVersionGE(12)
=> org.eclipse.jdt.core.dom.SwitchCase.$node.getExpressions()
;;

@id: jdt.internal.switchcase.setisexpr.to.setswitchlabeledrule
@severity: info
org.eclipse.jdt.core.dom.SwitchCase.$switchCase.setIsExpr($expression)
:: sourceVersionGE(12)
=> $switchCase.setSwitchLabeledRule($expression)
;;

@id: jdt.internal.switchcase.isexpr.to.isswitchlabeledrule
@severity: info
org.eclipse.jdt.core.dom.SwitchCase.$node.isExpr()
:: sourceVersionGE(12)
=> $node.isSwitchLabeledRule()
;;

@id: jdt.internal.switchcase.expression2property.to.expressions2property
@severity: info
org.eclipse.jdt.core.dom.SwitchCase.EXPRESSION_2_PROPERTY
:: sourceVersionGE(12)
=> org.eclipse.jdt.core.dom.SwitchCase.EXPRESSIONS2_PROPERTY
;;

@id: jdt.internal.switchcase.expressions.nodelist.constructor.arg.update
@severity: info
new org.eclipse.jdt.core.dom.ASTNode.NodeList(org.eclipse.jdt.core.dom.SwitchCase.EXPRESSION_2_PROPERTY)
:: sourceVersionGE(12)
=> new org.eclipse.jdt.core.dom.ASTNode.NodeList(org.eclipse.jdt.core.dom.SwitchCase.EXPRESSIONS2_PROPERTY)
;;

@id: jdt.internal.switchcase.property.comparison.update
@severity: info
$property == org.eclipse.jdt.core.dom.SwitchCase.EXPRESSION_2_PROPERTY
:: sourceVersionGE(12)
=> $property == org.eclipse.jdt.core.dom.SwitchCase.EXPRESSIONS2_PROPERTY
;;

